-- ============================================================
-- CATALOGO MAESTRO v1.5  (correr en Supabase -> SQL Editor)
-- Modelos de transformador + componentes (semielaborados) + BOM.
-- Origen: maestro de articulos SAP B1 (OITM) export 'SEMIELABORADOS.xlsx'.
-- Idempotente: re-ejecutable (CREATE IF NOT EXISTS + ON CONFLICT).
-- Integridad referencial: modelo_componentes referencia modelos y componentes.
-- ============================================================

create table if not exists modelos (
  codigo    text primary key,           -- = ItemCode (OITM)
  nombre    text not null,              -- = ItemName
  linea     text not null,             -- rural | distribucion | general
  fase      text,                       -- monofasico | bifasico | trifasico
  material  text,                       -- cobre | aluminio
  potencia  int,
  tension   int,
  montaje   text,
  tanque    text,
  activo    boolean not null default true
);

create table if not exists componentes (
  codigo      text primary key,         -- = ItemCode (OITM)
  descripcion text not null,
  categoria   text not null,            -- bobina_at|bobina_bt|prensayugo|parte_activa|herreria_*|accesorio
  sector_id   text,                     -- sector productivo de la PWA
  nivel       text,                     -- AT | BT (bobinas)
  linea       text,
  fase        text,
  material    text,
  potencia    int,
  tension     int,
  activo      boolean not null default true
);

create table if not exists modelo_componentes (
  modelo_codigo     text not null references modelos(codigo) on delete cascade,
  componente_codigo text not null references componentes(codigo) on delete cascade,
  primary key (modelo_codigo, componente_codigo)
);
create index if not exists idx_modelo_componentes_modelo on modelo_componentes(modelo_codigo);


-- ---------- Modelos ----------
on conflict (codigo) do update set nombre=excluded.nombre, linea=excluded.linea, fase=excluded.fase, material=excluded.material, potencia=excluded.potencia, tension=excluded.tension, montaje=excluded.montaje, tanque=excluded.tanque, activo=true;
on conflict (codigo) do update set nombre=excluded.nombre, linea=excluded.linea, fase=excluded.fase, material=excluded.material, potencia=excluded.potencia, tension=excluded.tension, montaje=excluded.montaje, tanque=excluded.tanque, activo=true;

